read -p "Enter domain name: " domain && mkdir -p /var/www/docker/keycloak && cd /var/www/docker/keycloak && mkdir -p "$domain" && cd "$domain" && curl -o docker-compose.external-cert.yml https://raw.githubusercontent.com/nahicyan/keycloak-production-docker-compose/refs/heads/master/docker-compose.external-cert.yml && vim docker-compose.external-cert.yml && curl -o .env.example https://raw.githubusercontent.com/nahicyan/keycloak-production-docker-compose/refs/heads/master/.env.example && cp .env.example .env && vim .env && sudo certbot certonly --nginx -d "$domain" && vim /etc/nginx/sites-available/"$domain" && sudo ln -s /etc/nginx/sites-available/"$domain" /etc/nginx/sites-enabled/ && sudo systemctl reload nginx && docker compose -f docker-compose.external-cert.yml up -d